SELECT model_name
FROM camera_models
WHERE model_id = 1;

SELECT model_name
FROM camera_models
ORDER BY model_name;

SELECT model_id, frame_rate_increase
FROM camera_specifications
WHERE frame_rate_increase = 'Yes';

SELECT MAX(max_brightness) AS max_brightness_level
FROM brightness_levels
WHERE model_id = 2;

SELECT model_id, frame_rate_increase, brightness_level_id 
FROM camera_specifications 
WHERE model_id = 1;

SELECT resolution_name, horizontal_pixels
FROM resolutions
WHERE horizontal_pixels > 3000;

SELECT model_name, description
FROM camera_models
WHERE model_id > 1;
